mapper.select:
select meeting_id, title, type, description, project_id, iteration_id, start_time, end_time, creator_id, status, create_at, update_at
from meeting where 1=1
and project_id = #{projectId}
and status = #{status}
order by start_time desc

mapper.update:
update meeting set title=#{title}, type=#{type}, description=#{description}, project_id=#{projectId},
    iteration_id=#{iterationId}, start_time=#{startTime}, end_time=#{endTime}, status=#{status}, update_at=#{updateAt}
where meeting_id = #{meetingId}
